/**
 * Theme type definitions and built-in theme catalog for T3 Code.
 *
 * This module provides the theme data contract consumed by the web client
 * and any future native clients. It intentionally has no runtime dependencies.
 */

export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * Semantic color values covering every major UI surface in T3 Code.
 * All values must be valid CSS <color> expressions.
 */
export type ThemeColors = {
  /** Main content area background */
  background: string;
  /** Primary text and icon color */
  foreground: string;
  /** Brand / accent color used for interactive highlights */
  accent: string;
  /** Navigation sidebar background */
  sidebar: string;
  /** Code editor pane background */
  editor: string;
  /** Integrated terminal background */
  terminal: string;
  /** Status bar (bottom strip) background */
  statusBar: string;
};

export type Theme = {
  id: ThemeId;
  /** Human-readable display label */
  label: string;
  /** True when this theme is designed for dark environments */
  dark: boolean;
  colors: ThemeColors;
};

export const BUILT_IN_THEMES: ReadonlyArray<Theme> = [
  {
    id: "t3-dark",
    label: "T3 Dark",
    dark: true,
    colors: {
      background: "#09090b",
      foreground: "#f4f4f5",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#0d0d10",
      editor: "#0b0b0e",
      terminal: "#060608",
      statusBar: "oklch(0.488 0.217 264)",
    },
  },
  {
    id: "t3-light",
    label: "T3 Light",
    dark: false,
    colors: {
      background: "#ffffff",
      foreground: "#18181b",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f4f4f5",
      editor: "#fafafa",
      terminal: "#f4f4f5",
      statusBar: "oklch(0.488 0.217 264)",
    },
  },
  {
    id: "t3-midnight",
    label: "T3 Midnight",
    dark: true,
    colors: {
      background: "#080d1a",
      foreground: "#e2e8f0",
      accent: "oklch(0.65 0.22 240)",
      sidebar: "#0a1020",
      editor: "#090e1c",
      terminal: "#060a14",
      statusBar: "oklch(0.55 0.22 240)",
    },
  },
] as const;

export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

/** Retrieve a built-in theme by id. Always returns a valid Theme. */
export function getBuiltInTheme(id: ThemeId): Theme {
  const found = BUILT_IN_THEMES.find((t) => t.id === id);
  // All ThemeId values are present in BUILT_IN_THEMES; fallback is a safety net.
  // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
  return found ?? (BUILT_IN_THEMES[0] as Theme);
}

/** Type guard for ThemeId. */
export function isThemeId(value: unknown): value is ThemeId {
  return value === "t3-dark" || value === "t3-light" || value === "t3-midnight";
}

