import { useCallback, useEffect, useSyncExternalStore } from "react";
import { type Theme, type ThemeId, getBuiltInTheme, isThemeId } from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:color-theme";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeId | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getStoredThemeId(): ThemeId | null {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return isThemeId(raw) ? raw : null;
  } catch {
    return null;
  }
}

/**
 * Apply a theme's colors as inline CSS custom properties on <html>.
 * Inline styles take precedence over stylesheet rules, so this reliably
 * overrides the default light/dark variable definitions in index.css.
 */
export function applyColorTheme(theme: Theme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  const isDark = theme.dark;
  // Use RGBA channel values for alpha-based derived colors.
  const fgChannels = isDark ? "255,255,255" : "0,0,0";
  const mutedFg = isDark ? "#a1a1aa" : "#71717a";

  // Core design tokens (match the variable names in index.css)
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--card", theme.colors.background);
  root.style.setProperty("--card-foreground", theme.colors.foreground);
  root.style.setProperty("--popover", theme.colors.background);
  root.style.setProperty("--popover-foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--primary-foreground", "#ffffff");
  root.style.setProperty("--secondary", `rgba(${fgChannels},0.04)`);
  root.style.setProperty("--secondary-foreground", theme.colors.foreground);
  root.style.setProperty("--muted", `rgba(${fgChannels},0.04)`);
  root.style.setProperty("--muted-foreground", mutedFg);
  root.style.setProperty("--accent", `rgba(${fgChannels},0.04)`);
  root.style.setProperty("--accent-foreground", theme.colors.foreground);
  root.style.setProperty("--border", `rgba(${fgChannels},${isDark ? "0.06" : "0.08"})`);
  root.style.setProperty("--input", `rgba(${fgChannels},${isDark ? "0.08" : "0.10"})`);
  root.style.setProperty("--ring", theme.colors.accent);

  // Theme-specific surface variables (new semantic slots)
  root.style.setProperty("--t3-sidebar", theme.colors.sidebar);
  root.style.setProperty("--t3-editor", theme.colors.editor);
  root.style.setProperty("--t3-terminal", theme.colors.terminal);
  root.style.setProperty("--t3-status-bar", theme.colors.statusBar);

  // OS-level color scheme (affects scrollbars, form controls, etc.)
  root.style.setProperty("color-scheme", isDark ? "dark" : "light");

  // Mark the active theme for CSS attribute targeting if needed.
  root.setAttribute("data-color-theme", theme.id);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

/**
 * Remove all inline CSS custom properties applied by applyColorTheme,
 * restoring control to the stylesheet-defined light/dark variables.
 */
export function clearColorTheme(suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  const props = [
    "--background",
    "--foreground",
    "--card",
    "--card-foreground",
    "--popover",
    "--popover-foreground",
    "--primary",
    "--primary-foreground",
    "--secondary",
    "--secondary-foreground",
    "--muted",
    "--muted-foreground",
    "--accent",
    "--accent-foreground",
    "--border",
    "--input",
    "--ring",
    "--t3-sidebar",
    "--t3-editor",
    "--t3-terminal",
    "--t3-status-bar",
    "color-scheme",
  ] as const;

  for (const prop of props) {
    root.style.removeProperty(prop);
  }
  root.removeAttribute("data-color-theme");

  if (suppressTransitions) {
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply stored theme immediately on module evaluation to prevent flash.
(function initColorTheme() {
  const id = getStoredThemeId();
  if (id !== null) {
    applyColorTheme(getBuiltInTheme(id));
  }
})();

function getSnapshot(): ThemeId | null {
  const id = getStoredThemeId();
  // Return the same reference when unchanged so useSyncExternalStore
  // can bail out without re-rendering.
  if (lastSnapshot === id) return lastSnapshot;
  lastSnapshot = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync theme changes made in other tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key !== STORAGE_KEY) return;
    const id = getStoredThemeId();
    if (id !== null) {
      applyColorTheme(getBuiltInTheme(id), true);
    } else {
      clearColorTheme(true);
    }
    emitChange();
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useColorTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme: Theme | null = themeId !== null ? getBuiltInTheme(themeId) : null;

  // Keep DOM in sync on mount and on themeId change.
  useEffect(() => {
    if (themeId !== null) {
      applyColorTheme(getBuiltInTheme(themeId));
    } else {
      clearColorTheme();
    }
  }, [themeId]);

  const setThemeId = useCallback((next: ThemeId | null) => {
    if (next !== null) {
      localStorage.setItem(STORAGE_KEY, next);
      applyColorTheme(getBuiltInTheme(next), true);
    } else {
      localStorage.removeItem(STORAGE_KEY);
      clearColorTheme(true);
    }
    emitChange();
  }, []);

  return { themeId, setThemeId, theme } as const;
}

