import { useColorTheme } from "~/hooks/useColorTheme";

/**
 * ThemeProvider is a renderless component that mounts the color theme side
 * effects into the React tree. Place it near the root so the DOM stays in
 * sync with the stored theme preference throughout the app's lifetime.
 *
 * The actual CSS custom property application happens in `useColorTheme`:
 * - Immediately on module evaluation (prevents flash-of-wrong-theme)
 * - In a useEffect on every themeId change
 * - Via localStorage events for cross-tab synchronization
 */
export function ThemeProvider(): null {
  useColorTheme();
  return null;
}

