import { BUILT_IN_THEMES, type ThemeId } from "@t3tools/shared/theme";
import { useColorTheme } from "~/hooks/useColorTheme";

/**
 * ThemeSelector renders a list of built-in color themes, each with a mini
 * UI preview swatch showing the sidebar, background, and status bar colors.
 * Selecting a theme persists the choice to localStorage and immediately
 * applies the CSS custom properties via `useColorTheme`.
 */
export function ThemeSelector() {
  const { themeId, setThemeId } = useColorTheme();

  return (
    <div className="space-y-2">
      <div className="space-y-2" role="radiogroup" aria-label="Color theme">
        {BUILT_IN_THEMES.map((theme) => {
          const selected = themeId === theme.id;
          return (
            <button
              key={theme.id}
              type="button"
              role="radio"
              aria-checked={selected}
              className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors ${
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent"
              }`}
              onClick={() => setThemeId(theme.id as ThemeId)}
            >
              {/* Mini UI preview */}
              <MiniPreview theme={theme} />

              {/* Theme label and variant */}
              <span className="flex flex-1 flex-col">
                <span className="text-sm font-medium text-foreground">{theme.label}</span>
                <span className="text-xs text-muted-foreground">
                  {theme.dark ? "Dark" : "Light"}
                </span>
              </span>

              {selected ? (
                <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      {themeId !== null ? (
        <div className="pt-1">
          <button
            type="button"
            className="text-xs text-muted-foreground underline-offset-2 hover:underline"
            onClick={() => setThemeId(null)}
          >
            Reset to system default
          </button>
        </div>
      ) : null}
    </div>
  );
}

type MiniPreviewProps = {
  theme: (typeof BUILT_IN_THEMES)[number];
};

/** A tiny window chrome mockup showing the sidebar, content, and status bar. */
function MiniPreview({ theme }: MiniPreviewProps) {
  const borderColor = theme.dark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.10)";

  return (
    <div
      className="flex h-10 w-16 shrink-0 flex-col overflow-hidden rounded-md shadow-sm"
      style={{ border: `1px solid ${borderColor}` }}
      aria-hidden="true"
    >
      {/* Main area: sidebar + content */}
      <div className="flex flex-1">
        {/* Sidebar strip */}
        <div
          className="w-4 shrink-0"
          style={{ background: theme.colors.sidebar }}
        />
        {/* Content area with accent dot */}
        <div
          className="relative flex flex-1 items-start justify-end p-1"
          style={{ background: theme.colors.editor }}
        >
          {/* Accent swatch in corner */}
          <div
            className="size-2 rounded-sm"
            style={{ background: theme.colors.accent }}
          />
        </div>
      </div>
      {/* Status bar strip */}
      <div
        className="h-1.5 w-full shrink-0"
        style={{ background: theme.colors.statusBar }}
      />
    </div>
  );
}

